selector_to_html = {"a[href=\"#equation-ca6fd3e9-be2e-4b61-ae43-7f11e95f96fe\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-ca6fd3e9-be2e-4b61-ae43-7f11e95f96fe\">\n\\[\\begin{equation}\n \\begin{aligned}\n  x_1' &amp;= t^{\\alpha-1} x_2 \\\\\n  x_2' &amp;= t^{\\alpha-1} \\left( -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2 \\right)\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#variables-de-estado\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\"><strong>Variables de Estado</strong><a class=\"headerlink\" href=\"#variables-de-estado\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#extension-conformable\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Extensi\u00f3n conformable<a class=\"headerlink\" href=\"#extension-conformable\" title=\"Link to this heading\">#</a></h3><p>Aplicando la derivada conformable de orden <span class=\"math notranslate nohighlight\">\\(\\alpha_{\\mathrm{frac}}\\)</span>:</p>", "a[href=\"#pendulo-simple\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">P\u00e9ndulo simple<a class=\"headerlink\" href=\"#pendulo-simple\" title=\"Link to this heading\">#</a></h1><p>Para establecer una l\u00ednea de base, primero se define el sistema cl\u00e1sico del p\u00e9ndulo no lineal con amortiguamiento. Las ecuaciones gobernantes son:</p><p><strong>Sistema cl\u00e1sico original del p\u00e9ndulo</strong></p>", "a[href=\"#interpretacion-fisica\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Interpretaci\u00f3n f\u00edsica<a class=\"headerlink\" href=\"#interpretacion-fisica\" title=\"Link to this heading\">#</a></h2><p>El factor de escalamiento dependiente del tiempo <span class=\"math notranslate nohighlight\">\\(t^{\\alpha-1}\\)</span> tiene implicaciones f\u00edsicas interesantes:</p>", "a[href=\"#equation-e62b935d-202d-4c3c-a84c-bb630584aeb4\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-e62b935d-202d-4c3c-a84c-bb630584aeb4\">\n\\[\\begin{equation}\n \\begin{aligned}\n  t^{1-\\alpha} x_1' &amp;= x_2 \\quad \\Rightarrow \\quad x_1' = t^{\\alpha-1} x_2 \\\\\n  t^{1-\\alpha} x_2' &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2 \\quad \\Rightarrow \\quad x_2' = t^{\\alpha-1} \\left( -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2 \\right)\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#pendulo-con-efectos-de-chorro-de-aire\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">P\u00e9ndulo con efectos de chorro de aire<a class=\"headerlink\" href=\"#pendulo-con-efectos-de-chorro-de-aire\" title=\"Link to this heading\">#</a></h2><p>La ecuaci\u00f3n cl\u00e1sica del p\u00e9ndulo con efectos de chorro de aire fue propuesta por <span id=\"id1\">Hasan <em>et al.</em> (<a class=\"reference internal\" href=\"../references.html#id3\" title=\"Hasan, M. S., Deepu, P., Kumar, K., Agrawal, A., &amp; Meena, D. K. (2023). Oscillation decay of a pendulum by an air jet. Physics Letters A, 481, 129003.\">2023</a>)</span></p>", "a[href=\"#equation-4a8e6eb0-f3c4-4280-9db3-44f2b75c014e\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-4a8e6eb0-f3c4-4280-9db3-44f2b75c014e\">\n\\[\\begin{equation}\n \\begin{aligned}\n  x_1' &amp;= x_2 \\\\\n  x_2' &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-3b85ac76-f0cd-44c2-a0ed-f0ff59c12107\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-3b85ac76-f0cd-44c2-a0ed-f0ff59c12107\">\n\\[\\begin{equation}\n \\begin{aligned}\n  D^\\alpha_t x_1 &amp;= x_2 \\\\\n  D^\\alpha_t x_2 &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#pendulo-no-lineal-clasico-con-amortiguamiento\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">P\u00e9ndulo no lineal cl\u00e1sico con amortiguamiento<a class=\"headerlink\" href=\"#pendulo-no-lineal-clasico-con-amortiguamiento\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#parametros-del-sistema\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\"><strong>Par\u00e1metros del Sistema</strong><a class=\"headerlink\" href=\"#parametros-del-sistema\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#modelado\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelado<a class=\"headerlink\" href=\"#modelado\" title=\"Link to this heading\">#</a></h2><h3>P\u00e9ndulo no lineal cl\u00e1sico con amortiguamiento<a class=\"headerlink\" href=\"#pendulo-no-lineal-clasico-con-amortiguamiento\" title=\"Link to this heading\">#</a></h3>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: false,
                placement: 'auto-start', maxWidth: 500, interactive: true, boundary: document.body, appendTo: document.body,
                onShow(instance) {MathJax.typesetPromise([instance.popper]).then(() => {var isFirefox=typeof InstallTrigger!=='undefined';if(isFirefox&&window.MathJax&&MathJax.startup&&MathJax.startup.output&&MathJax.startup.output.name==="SVG"){const svgs=instance.popper.querySelectorAll('svg');svgs.forEach(svg=>{let bbox=svg.getBBox(),x=bbox.x,y=bbox.y,width=bbox.width,height=bbox.height;svg.setAttribute('width',width);svg.setAttribute('height',height);svg.setAttribute('viewBox',`${x} ${y} ${width} ${height}`);});let rescale=0.015;svgs.forEach(svg=>{let bbox=svg.getBBox(),width=bbox.width,height=bbox.height;svg.setAttribute('width',width*rescale);svg.setAttribute('height',height*rescale);});}});},
            });
        };
    };
    console.log("tippy tips loaded!");
};
